const frontStyle = {
  position: "absolute",
  width: "100%",
  height: "100%",
  backfaceVisibility: "hidden",
  display: "flex",
  flexDirection: "column",
  justifyContent: "center",
  alignItems: "center",     // <-- aseguro alineación horizontal centrada
  padding: "1rem",
  textAlign: "center",      // <-- centro texto
};

const backStyle = {
  ...frontStyle,
  transform: "rotateY(180deg)",
  overflowY: card.backType === "list" ? "auto" : "hidden",
  paddingLeft: "1rem",
  paddingRight: "1rem",
};
